{"version":3,"sources":["templates/taxi-pricing.scss","templates/taxi-pricing.css"],"names":[],"mappings":"AAAA;EACI,kBAAA;EACA,aAAA;EACA,UAAA;EACA,yBAAA;EACA,aAAA;ACCJ;;ADEA;EACI,WAAA;EACA,YAAA;EACA,kBAAA;EACA,yBAAA;EACA,kBAAA;EACA,UAAA;EACA,UAAA;ACCJ;;ADEA;EACI,SAAA;ACCJ;;ADEA;EACI,aAAA;ACCJ;;ADEA;EACI,gBAAA;EACA,WAAA;EACA,kBAAA;EACA,gBAAA;EACA,yBAAA;EACA,yCAAA;ACCJ;;ADEA;EACI,yBAAA;EACA,YAAA;EACA,kBAAA;EACA,eAAA;EACA,iBAAA;ACCJ;;ADEA;EACI,aAAA;EACA,uBAAA;ACCJ;;ADEA;EACI,aAAA;EACA,qBAAA;EACA,mBAAA;ACCJ;;ADEA;EACI,cAAA;EACA,WAAA;EACA,kBAAA;EACA,yBAAA;EACA,kBAAA;EACA,eAAA;ACCJ;;ADEA;EACI,WAAA;EACA,yBAAA;EACA,cAAA;ACCJ;;ADEA;EACI,yBAAA;EAEA,YAAA;EACA,YAAA;EACA,kBAAA;EACA,aAAA;EACA,WAAA;EACA,eAAA;EACA,gBAAA;EACA,eAAA;EACA,mBAAA;ACAJ;;ADGA;EACI,eAAA;EACA,gBAAA;ACAJ;;ADGA;EACI,cAAA;EACA,qBAAA;ACAJ","file":"taxi-pricing.css","sourcesContent":[".timeline-line {\n    position: absolute;\n    bottom: 150px;\n    width: 2px;\n    background-color: #e5e5e5;\n    height: 154px;\n}\n\n.timeline-dot {\n    width: 12px;\n    height: 12px;\n    border-radius: 50%;\n    background-color: #d1d1d1;\n    position: absolute;\n    left: 20px;\n    z-index: 1;\n}\n\n.dot-pickup {\n    top: 30px;\n}\n\n.dot-dropoff {\n    bottom: 150px;\n}\n\n.price-card {\n    max-width: 500px;\n    width: 100%;\n    border-radius: 8px;\n    overflow: hidden;\n    border: 1px solid #eaeaea;\n    box-shadow: 0 2px 5px rgba(0, 0, 0, 0.05);\n}\n\n.price-header {\n    background-color: #4b2e83;\n    color: white;\n    padding: 16px 20px;\n    font-size: 24px;\n    font-weight: bold;\n}\n\n.price-body {\n    padding: 20px;\n    background-color: white;\n}\n\n.list-item {\n    display: flex;\n    align-items: baseline;\n    margin-bottom: 10px;\n}\n\n.list-item .dot {\n    min-width: 8px;\n    height: 8px;\n    border-radius: 50%;\n    background-color: #9ca3af;\n    margin-right: 10px;\n    margin-top: 8px;\n}\n\n.divider {\n    height: 1px;\n    background-color: #e5e7eb;\n    margin: 20px 0;\n}\n\n.book-now-btn {\n    background-color: #3b2366;\n    ;\n    color: white;\n    border: none;\n    border-radius: 4px;\n    padding: 12px;\n    width: 100%;\n    font-size: 18px;\n    font-weight: 500;\n    cursor: pointer;\n    margin-bottom: 15px;\n}\n\n.footer-text {\n    font-size: 14px;\n    line-height: 1.4;\n}\n\n.footer-link {\n    color: #6937b6;\n    text-decoration: none;\n}",".timeline-line {\n  position: absolute;\n  bottom: 150px;\n  width: 2px;\n  background-color: #e5e5e5;\n  height: 154px;\n}\n\n.timeline-dot {\n  width: 12px;\n  height: 12px;\n  border-radius: 50%;\n  background-color: #d1d1d1;\n  position: absolute;\n  left: 20px;\n  z-index: 1;\n}\n\n.dot-pickup {\n  top: 30px;\n}\n\n.dot-dropoff {\n  bottom: 150px;\n}\n\n.price-card {\n  max-width: 500px;\n  width: 100%;\n  border-radius: 8px;\n  overflow: hidden;\n  border: 1px solid #eaeaea;\n  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.05);\n}\n\n.price-header {\n  background-color: #4b2e83;\n  color: white;\n  padding: 16px 20px;\n  font-size: 24px;\n  font-weight: bold;\n}\n\n.price-body {\n  padding: 20px;\n  background-color: white;\n}\n\n.list-item {\n  display: flex;\n  align-items: baseline;\n  margin-bottom: 10px;\n}\n\n.list-item .dot {\n  min-width: 8px;\n  height: 8px;\n  border-radius: 50%;\n  background-color: #9ca3af;\n  margin-right: 10px;\n  margin-top: 8px;\n}\n\n.divider {\n  height: 1px;\n  background-color: #e5e7eb;\n  margin: 20px 0;\n}\n\n.book-now-btn {\n  background-color: #3b2366;\n  color: white;\n  border: none;\n  border-radius: 4px;\n  padding: 12px;\n  width: 100%;\n  font-size: 18px;\n  font-weight: 500;\n  cursor: pointer;\n  margin-bottom: 15px;\n}\n\n.footer-text {\n  font-size: 14px;\n  line-height: 1.4;\n}\n\n.footer-link {\n  color: #6937b6;\n  text-decoration: none;\n}"]}